class Fenw(private val size: Int) {
    private val tree = LongArray(size + 1)

    fun update(i: Int, delta: Long) {
        var idx = i + 1
        while (idx <= size) {
            tree[idx] += delta
            idx += idx and (-idx)
        }
    }

    private fun prefixSum(i: Int): Long {
        var idx = i + 1
        var s = 0L
        while (idx > 0) {
            s += tree[idx]
            idx -= idx and (-idx)
        }
        return s
    }

    fun rangeQuery(l: Int, r: Int): Long {
        if (l > r) {
            return 0
        }
        val rightPart = prefixSum(r)
        val leftPart = if (l > 0) prefixSum(l - 1) else 0L
        return rightPart - leftPart
    }
}

fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val n = nums.size
    val table = IntArray(65)
    table[1] = 0
    for (i in 2..64) {
        table[i] = 1 + table[i.countOneBits()]
    }

    fun getDepth(x: Long): Int {
        if (x == 1L) return 0
        return 1 + table[x.countOneBits()]
    }

    val currentNums = nums.copyOf()
    val depthArr = IntArray(n) { i -> getDepth(currentNums[i]) }

    val fenwTrees = Array(6) { Fenw(n) }

    for (i in 0 until n) {
        val d = depthArr[i]
        if (d in 0..5) {
            fenwTrees[d].update(i, 1)
        }
    }

    val ansList = mutableListOf<Long>()

    for (query in queries) {
        if (query[0] == 1L) {
            val l = query[1].toInt()
            val r = query[2].toInt()
            val k = query[3].toInt()
            if (k in 0..5) {
                ansList.add(fenwTrees[k].rangeQuery(l, r))
            } else {
                ansList.add(0)
            }
        } else if (query[0] == 2L) {
            val idx = query[1].toInt()
            val newVal = query[2]

            val oldDepth = depthArr[idx]
            val newDepth = getDepth(newVal)

            if (oldDepth in 0..5) {
                fenwTrees[oldDepth].update(idx, -1)
            }
            if (newDepth in 0..5) {
                fenwTrees[newDepth].update(idx, 1)
            }

            currentNums[idx] = newVal
            depthArr[idx] = newDepth
        }
    }

    return ansList.toTypedArray()
}
```

### Explanation
1. **Precomputation**:
   - The `table` array is precomputed for numbers 1 to 64. For each number `i`, `table[i]` is `1 + table[popcount(i)]`, with `table[1] = 0`.

2. **Depth Calculation**:
   - The function `getDepth` computes the popcount-depth for any number `x` by leveraging the precomputed table. If `x` is 1, the depth is 0; otherwise, it's `1 + table[popcount(x)]`.

3. **Initialization**:
   - The initial array is copied to `currentNums`, and `depthArr` stores the depth of each element. Fenwick trees for depths 0 to 5 are initialized based on `depthArr`.

4. **Query Processing**:
   - **Type 1 Queries**: For each count query `[1, l, r, k]`, the result is obtained by querying the Fenwick tree for depth `k` over the range `[l, r]`.
   - **Type 2 Queries**: For each update `[2, idx, val]`, the depth of the new value is computed. The Fenwick tree for the old depth is decremented, and the tree for the new depth is incremented. `currentNums` and `depthArr` are updated accordingly.

This approach efficiently handles both types of queries with logarithmic time complexity for updates and range queries, leveraging Fenwick trees for optimal performance.

