class SegTree {
    var tree: [[Int64]]
    var n: Int

    init(_ depths: [Int]) {
        n = depths.count
        tree = Array(repeating: [0,0,0,0,0,0], count: 4 * n)
        build(node: 0, l: 0, r: n-1, depths: depths)
    }

    private func build(node: Int, l: Int, r: Int, depths: [Int]) {
        if l == r {
            let d = depths[l]
            tree[node] = [0,0,0,0,0,0]
            if d >= 0 && d < 6 {
                tree[node][d] = 1
            }
            return
        }
        let mid = (l + r) / 2
        let leftChild = 2 * node + 1
        let rightChild = 2 * node + 2
        build(node: leftChild, l: l, r: mid, depths: depths)
        build(node: rightChild, l: mid+1, r: r, depths: depths)
        for i in 0..<6 {
            tree[node][i] = tree[leftChild][i] + tree[rightChild][i]
        }
    }

    public func update(idx: Int, newDepth: Int) {
        _update(node: 0, segL: 0, segR: n-1, idx: idx, newDepth: newDepth)
    }

    private func _update(node: Int, segL: Int, segR: Int, idx: Int, newDepth: Int) {
        if segL == segR {
            tree[node] = [0,0,0,0,0,0]
            if newDepth >= 0 && newDepth < 6 {
                tree[node][newDepth] = 1
            }
        } else {
            let mid = (segL + segR) / 2
            if idx <= mid {
                _update(node: 2*node+1, segL: segL, segR: mid, idx: idx, newDepth: newDepth)
            } else {
                _update(node: 2*node+2, segL: mid+1, segR: segR, idx: idx, newDepth: newDepth)
            }
            let leftChild = 2 * node + 1
            let rightChild = 2 * node + 2
            for i in 0..<6 {
                tree[node][i] = tree[leftChild][i] + tree[rightChild][i]
            }
        }
    }

    public func query(l: Int, r: Int) -> [Int64] {
        return _query(node: 0, segL: 0, segR: n-1, l: l, r: r)
    }

    private func _query(node: Int, segL: Int, segR: Int, l: Int, r: Int) -> [Int64] {
        if r < segL || segR < l {
            return [0,0,0,0,0,0]
        }
        if l <= segL && segR <= r {
            return tree[node]
        }
        let mid = (segL + segR) / 2
        let leftRes = _query(node: 2*node+1, segL: segL, segR: mid, l: l, r: r)
        let rightRes = _query(node: 2*node+2, segL: mid+1, segR: segR, l: l, r: r)
        var res = [Int64](repeating: 0, count: 6)
        for i in 0..<6 {
            res[i] = leftRes[i] + rightRes[i]
        }
        return res
    }
}

func solve(nums: Array<Int64>, queries: Array<Array<Int64>>) -> Array<Int64> {
    let n = nums.count
    var depths = [Int]()
    for num in nums {
        depths.append(get_depth(num))
    }
    let segTree = SegTree(depths)
    var answers: [Int64] = []
    for q in queries {
        let type = q[0]
        if type == 1 {
            let l = Int(q[1])
            let r = Int(q[2])
            let k = Int(q[3])
            let cnts = segTree.query(l: l, r: r)
            if k >= 0 && k < 6 {
                answers.append(cnts[k])
            } else {
                answers.append(0)
            }
        } else if type == 2 {
            let idx = Int(q[1])
            let val = q[2]
            let newDepth = get_depth(val)
            segTree.update(idx: idx, newDepth: newDepth)
        }
    }
    return answers
}

private func get_depth(_ x: Int64) -> Int {
    if x == 1 {
        return 0
    }
    var steps = 0
    var curr = x
    while curr != 1 {
        steps += 1
        curr = Int64(popcount(curr))
    }
    return steps
}

private func popcount(_ x: Int64) -> Int {
    var n = x
    var count = 0
    while n != 0 {
        count += 1
        n = n & (n - 1)
    }
    return count
}
