fun solve(nums: Array<Int64>, queries: Array<Array<Int64>>): Array<Int64> {
    val n = nums.size
    fun getDepth(x0: Int64): Int {
        if (x0 == 1L) return 0
        var x = x0
        var cnt = 0
        while (x != 1L) {
            cnt++
            var popcnt = 0
            var t = x
            for (i in 0 until 64) {
                popcnt += (t and 1L).toInt()
                t = t ushr 1
            }
            x = popcnt.toLong()
        }
        return cnt
    }

    val depthArray = IntArray(n)
    val fenw = Array(6) { IntArray(n + 1) }

    fun update(k: Int, index: Int, delta: Int) {
        var idx = index + 1
        while (idx <= n) {
            fenw[k][idx] += delta
            idx += idx and -idx
        }
    }

    fun prefix(k: Int, pos: Int): Int {
        if (pos < 0) return 0
        var idx = pos + 1
        var s = 0
        while (idx > 0) {
            s += fenw[k][idx]
            idx -= idx and -idx
        }
        return s
    }

    fun query(k: Int, l: Int, r: Int): Int {
        if (l > r) return 0
        return prefix(k, r) - prefix(k, l - 1)
    }

    for (i in 0 until n) {
        val d = getDepth(nums[i])
        depthArray[i] = d
        if (d in 0..5) {
            update(d, i, 1)
        }
    }

    val result = mutableListOf<Int64>()
    for (q in queries) {
        if (q[0] == 1L) {
            val l = q[1].toInt()
            val r = q[2].toInt()
            val kVal = q[3].toInt()
            val cnt = if (kVal in 0..5) query(kVal, l, r) else 0
            result.add(cnt.toLong())
        } else if (q[0] == 2L) {
            val idx = q[1].toInt()
            val newVal = q[2]
            val oldDepth = depthArray[idx]
            if (oldDepth in 0..5) {
                update(oldDepth, idx, -1)
            }
            val newDepth = getDepth(newVal)
            depthArray[idx] = newDepth
            if (newDepth in 0..5) {
                update(newDepth, idx, 1)
            }
        }
    }
    return result.toTypedArray()
}
