class Fenw {
    int n;
    int[] tree;

    Fenw(int size) {
        n = size;
        tree = new int[n + 1];
    }

    void update(int index, int delta) {
        int i = index + 1;
        while (i <= n) {
            tree[i] += delta;
            i += i & -i;
        }
    }

    int prefix(int index) {
        if (index < 0) {
            return 0;
        }
        int s = 0;
        int i = index + 1;
        while (i > 0) {
            s += tree[i];
            i -= i & -i;
        }
        return s;
    }

    int range(int l, int r) {
        if (l == 0) {
            return prefix(r);
        } else {
            return prefix(r) - prefix(l - 1);
        }
    }
}

fun popcount(x: Int64): Int {
    var count = 0;
    var n = x;
    while (n != 0.toInt64()) {
        count += 1;
        n = n & (n - 1.toInt64());
    }
    return count;
}

fun compute_depth(x: Int64): Int {
    if (x == 1.toInt64()) {
        return 0;
    }
    var steps = 0;
    var cur = x;
    while (cur != 1.toInt64()) {
        steps += 1;
        cur = popcount(cur).toInt64();
    }
    return steps;
}

fun solve(nums: Array<Int64>, queries: Array<Array<Int64>>): Array<Int64> {
    val n = nums.size;
    val depthArr = IntArray(n);
    for (i in 0 until n) {
        depthArr[i] = compute_depth(nums[i]);
    }

    val fenws = Array<Fenw>(6) { Fenw(n) };
    for (k in 0..5) {
        fenws[k] = Fenw(n);
    }

    for (k in 0..5) {
        for (i in 0 until n) {
            if (depthArr[i] == k) {
                fenws[k].update(i, 1);
            }
        }
    }

    val ans = mutableListOf<Int64>();
    for (q in queries) {
        if (q[0] == 1.toInt64()) {
            val l = q[1].toInt();
            val r = q[2].toInt();
            val k_val = q[3].toInt();
            if (k_val < 0 || k_val > 5) {
                ans.add(0);
            } else {
                val res = fenws[k_val].range(l, r);
                ans.add(res.toLong());
            }
        } else {
            val idx = q[1].toInt();
            val new_val = q[2];
            val new_depth = compute_depth(new_val);
            val old_depth = depthArr[idx];
            if (old_depth != new_depth) {
                if (old_depth >= 0 && old_depth <= 5) {
                    fenws[old_depth].update(idx, -1);
                }
                if (new_depth >= 0 && new_depth <= 5) {
                    fenws[new_depth].update(idx, 1);
                }
                depthArr[idx] = new_depth;
            }
        }
    }

    return ans.toTypedArray();
}
